{"version":3,"sources":["templates/hotel.scss","templates/hotel.css"],"names":[],"mappings":"AAAC;EACI,oCAAA;EACA,kBAAA;EACA,yBAAA;EACA,eAAA;EACA,wCAAA;EACA,wBAAA;EACA,gCAAA;EACA,mBAAA;EAGA,oBAAA;ACDL;;ADIC;;EAEI,yBAAA;EACA,YAAA;EACA,0BAAA;EACA,4BAAA;ACDL;;ADKC;EACI,yBAAA;ACFL;;ADKC;EACI,cAAA;ACFL;;ADKC;EACI,oBAAA;ACFL;;ADKC;EACI,yBAAA;ACFL;;ADKC;EACI,2BAAA;EACA,0CAAA;ACFL;;ADKC;EACI,cAAA;ACFL;;ADKC;EACI,yBAAA;ACFL;;ADMK;EACI,sBAAA;EACA,uBAAA;ACHT;;ADOC;EACI,+BAAA;KAAA,4BAAA;EACA,aAAA;EACA,uBAAA;EACA,2BAAA;ACJL;;ADOC;EACI;IACI,WAAA;ECJP;AACF","file":"hotel.css","sourcesContent":[" .rating-btn {\n     border: 2px solid #3F1E63 !important;\n     /* Outline color */\n     color: #3F1E63 !important;\n     /* Text color */\n     background-color: transparent !important;\n     /* Default transparent */\n     transition: all 0.3s ease-in-out;\n     border-radius: 20px;\n     //  padding: 2px 15px;\n     //  font-size: 0.9rem;\n     transition: all 0.3s;\n }\n\n .rating-btn:hover,\n .rating-btn.active {\n     background-color: #3F1E63;\n     color: white;\n     font-style: 6px !important;\n     padding: 2px 10px !important;\n }\n\n //   card css \n .purple-bg {\n     background-color: #4b2e83;\n }\n\n .purple-text {\n     color: #4b2e83;\n }\n\n .card {\n     transition: all 0.3s;\n }\n\n .card.selected {\n     border: 2px solid #4b2e83;\n }\n\n .card:hover {\n     transform: translateY(-5px);\n     box-shadow: 0 10px 20px rgba(0, 0, 0, 0.1);\n }\n\n .star-rating {\n     color: #FFD700;\n }\n\n .light-purple-bg {\n     background-color: #e6e1f0;\n }\n\n .hotel-card {\n     .carousel-indicators .indicators {\n         width: 10px !important;\n         height: 10px !important;\n     }\n }\n\n .hotel-card-img {\n     object-fit: cover !important;\n     height: 200px;\n     width: 140px !important;\n     max-width: 180px !important;\n }\n\n @media (max-width: 767px) {\n     .w-48 {\n         width: 100%\n     }\n }",".rating-btn {\n  border: 2px solid #3F1E63 !important;\n  /* Outline color */\n  color: #3F1E63 !important;\n  /* Text color */\n  background-color: transparent !important;\n  /* Default transparent */\n  transition: all 0.3s ease-in-out;\n  border-radius: 20px;\n  transition: all 0.3s;\n}\n\n.rating-btn:hover,\n.rating-btn.active {\n  background-color: #3F1E63;\n  color: white;\n  font-style: 6px !important;\n  padding: 2px 10px !important;\n}\n\n.purple-bg {\n  background-color: #4b2e83;\n}\n\n.purple-text {\n  color: #4b2e83;\n}\n\n.card {\n  transition: all 0.3s;\n}\n\n.card.selected {\n  border: 2px solid #4b2e83;\n}\n\n.card:hover {\n  transform: translateY(-5px);\n  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.1);\n}\n\n.star-rating {\n  color: #FFD700;\n}\n\n.light-purple-bg {\n  background-color: #e6e1f0;\n}\n\n.hotel-card .carousel-indicators .indicators {\n  width: 10px !important;\n  height: 10px !important;\n}\n\n.hotel-card-img {\n  object-fit: cover !important;\n  height: 200px;\n  width: 140px !important;\n  max-width: 180px !important;\n}\n\n@media (max-width: 767px) {\n  .w-48 {\n    width: 100%;\n  }\n}"]}